import{_ as t,o as a,c as e,ag as s}from"./chunks/framework.Vng7Hdlh.js";const g=JSON.parse('{"title":"Dashboard Overview","description":"","frontmatter":{},"headers":[],"relativePath":"admin-ui/dashboard.md","filePath":"admin-ui/dashboard.md"}'),o={name:"admin-ui/dashboard.md"};function r(n,i,l,c,h,d){return a(),e("div",null,[...i[0]||(i[0]=[s('<h1 id="dashboard-overview" tabindex="-1">Dashboard Overview <a class="header-anchor" href="#dashboard-overview" aria-label="Permalink to &quot;Dashboard Overview&quot;">​</a></h1><p>The Dashboard is the central hub of the SMART on FHIR Admin UI, providing a comprehensive overview of your healthcare platform&#39;s status, metrics, and quick access to all management functions.</p><h2 id="🏠-dashboard-layout" tabindex="-1">🏠 Dashboard Layout <a class="header-anchor" href="#🏠-dashboard-layout" aria-label="Permalink to &quot;🏠 Dashboard Layout&quot;">​</a></h2><h3 id="system-health-monitoring" tabindex="-1">System Health Monitoring <a class="header-anchor" href="#system-health-monitoring" aria-label="Permalink to &quot;System Health Monitoring&quot;">​</a></h3><p>The dashboard displays real-time system health indicators:</p><ul><li><strong>🟢 Active Components</strong>: Shows which services are running (OAuth Server, FHIR Proxy, WebSocket)</li><li><strong>📊 Performance Metrics</strong>: Response times, memory usage, and throughput statistics</li><li><strong>⚠️ Alerts</strong>: System warnings, errors, and maintenance notifications</li><li><strong>🔄 Last Update</strong>: Real-time refresh indicators for live data</li></ul><h3 id="quick-actions-panel" tabindex="-1">Quick Actions Panel <a class="header-anchor" href="#quick-actions-panel" aria-label="Permalink to &quot;Quick Actions Panel&quot;">​</a></h3><p>Direct access to common administrative tasks:</p><ul><li><strong>➕ Add User</strong>: Quickly register new healthcare users</li><li><strong>📱 Register App</strong>: Fast SMART application registration</li><li><strong>🏥 Add FHIR Server</strong>: Connect new FHIR endpoints</li><li><strong>🎯 Configure Scopes</strong>: Set up permission templates</li><li><strong>🚀 Launch Context</strong>: Create clinical contexts</li><li><strong>👁️ Monitor OAuth</strong>: View real-time authorization flows</li></ul><h3 id="statistics-overview" tabindex="-1">Statistics Overview <a class="header-anchor" href="#statistics-overview" aria-label="Permalink to &quot;Statistics Overview&quot;">​</a></h3><p>Key platform metrics at a glance:</p><h4 id="user-statistics" tabindex="-1">User Statistics <a class="header-anchor" href="#user-statistics" aria-label="Permalink to &quot;User Statistics&quot;">​</a></h4><ul><li><strong>Total Users</strong>: Count of registered healthcare users</li><li><strong>Active Sessions</strong>: Currently authenticated users</li><li><strong>Recent Logins</strong>: Login activity in the last 24 hours</li><li><strong>FHIR Associations</strong>: Users with Person resource links</li></ul><h4 id="application-statistics" tabindex="-1">Application Statistics <a class="header-anchor" href="#application-statistics" aria-label="Permalink to &quot;Application Statistics&quot;">​</a></h4><ul><li><strong>Registered Apps</strong>: Total SMART applications</li><li><strong>Active Apps</strong>: Applications with recent activity</li><li><strong>Authorization Requests</strong>: OAuth flows in progress</li><li><strong>Successful Launches</strong>: Completed app launches</li></ul><h4 id="fhir-server-statistics" tabindex="-1">FHIR Server Statistics <a class="header-anchor" href="#fhir-server-statistics" aria-label="Permalink to &quot;FHIR Server Statistics&quot;">​</a></h4><ul><li><strong>Connected Servers</strong>: Total configured FHIR endpoints</li><li><strong>Healthy Servers</strong>: Servers responding normally</li><li><strong>Response Time</strong>: Average server response latency</li><li><strong>Data Volume</strong>: Recent FHIR operations</li></ul><h4 id="oauth-analytics" tabindex="-1">OAuth Analytics <a class="header-anchor" href="#oauth-analytics" aria-label="Permalink to &quot;OAuth Analytics&quot;">​</a></h4><ul><li><strong>Authorization Flows</strong>: Total OAuth requests</li><li><strong>Success Rate</strong>: Percentage of successful authorizations</li><li><strong>Error Rate</strong>: Failed authorization attempts</li><li><strong>Flow Types</strong>: Breakdown by authorization grant type</li></ul><h2 id="🔍-real-time-monitoring" tabindex="-1">🔍 Real-time Monitoring <a class="header-anchor" href="#🔍-real-time-monitoring" aria-label="Permalink to &quot;🔍 Real-time Monitoring&quot;">​</a></h2><h3 id="live-updates" tabindex="-1">Live Updates <a class="header-anchor" href="#live-updates" aria-label="Permalink to &quot;Live Updates&quot;">​</a></h3><p>The dashboard automatically refreshes every 30 seconds to provide:</p><ul><li>Current system status</li><li>Updated metrics and counters</li><li>New alerts and notifications</li><li>Fresh performance data</li></ul><h3 id="websocket-integration" tabindex="-1">WebSocket Integration <a class="header-anchor" href="#websocket-integration" aria-label="Permalink to &quot;WebSocket Integration&quot;">​</a></h3><p>Real-time updates via WebSocket connections:</p><ul><li>OAuth flow notifications</li><li>System health changes</li><li>User activity alerts</li><li>FHIR server status updates</li></ul><h2 id="📊-visual-components" tabindex="-1">📊 Visual Components <a class="header-anchor" href="#📊-visual-components" aria-label="Permalink to &quot;📊 Visual Components&quot;">​</a></h2><h3 id="health-status-indicators" tabindex="-1">Health Status Indicators <a class="header-anchor" href="#health-status-indicators" aria-label="Permalink to &quot;Health Status Indicators&quot;">​</a></h3><ul><li><strong>🟢 Green</strong>: System operating normally</li><li><strong>🟡 Yellow</strong>: Minor issues or warnings</li><li><strong>🔴 Red</strong>: Critical issues requiring attention</li><li><strong>⚪ Gray</strong>: Service unavailable or disabled</li></ul><h3 id="metric-cards" tabindex="-1">Metric Cards <a class="header-anchor" href="#metric-cards" aria-label="Permalink to &quot;Metric Cards&quot;">​</a></h3><p>Each metric is displayed in an interactive card showing:</p><ul><li>Current value with trend indicators</li><li>Percentage change from previous period</li><li>Historical trend visualization</li><li>Quick action buttons for related tasks</li></ul><h3 id="activity-timeline" tabindex="-1">Activity Timeline <a class="header-anchor" href="#activity-timeline" aria-label="Permalink to &quot;Activity Timeline&quot;">​</a></h3><p>Recent platform activity including:</p><ul><li>User registrations and logins</li><li>Application launches</li><li>System events and changes</li><li>Error occurrences and resolutions</li></ul><h2 id="🛠️-dashboard-actions" tabindex="-1">🛠️ Dashboard Actions <a class="header-anchor" href="#🛠️-dashboard-actions" aria-label="Permalink to &quot;🛠️ Dashboard Actions&quot;">​</a></h2><h3 id="system-management" tabindex="-1">System Management <a class="header-anchor" href="#system-management" aria-label="Permalink to &quot;System Management&quot;">​</a></h3><ul><li><strong>Refresh Data</strong>: Manual system refresh</li><li><strong>View Logs</strong>: Access to system and audit logs</li><li><strong>Export Reports</strong>: Generate platform usage reports</li><li><strong>System Settings</strong>: Access to global configuration</li></ul><h3 id="quick-navigation" tabindex="-1">Quick Navigation <a class="header-anchor" href="#quick-navigation" aria-label="Permalink to &quot;Quick Navigation&quot;">​</a></h3><p>The dashboard provides one-click access to:</p><ul><li>User management section</li><li>SMART app registry</li><li>FHIR server configuration</li><li>Scope management tools</li><li>Launch context builder</li><li>OAuth monitoring dashboard</li><li>Identity provider settings</li></ul><h2 id="📱-mobile-responsiveness" tabindex="-1">📱 Mobile Responsiveness <a class="header-anchor" href="#📱-mobile-responsiveness" aria-label="Permalink to &quot;📱 Mobile Responsiveness&quot;">​</a></h2><p>The dashboard is fully responsive and optimized for:</p><ul><li><strong>Desktop</strong>: Full-featured experience with all metrics</li><li><strong>Tablet</strong>: Optimized layout with key information</li><li><strong>Mobile</strong>: Essential metrics and quick actions</li></ul><h2 id="🔔-notifications-and-alerts" tabindex="-1">🔔 Notifications and Alerts <a class="header-anchor" href="#🔔-notifications-and-alerts" aria-label="Permalink to &quot;🔔 Notifications and Alerts&quot;">​</a></h2><h3 id="system-notifications" tabindex="-1">System Notifications <a class="header-anchor" href="#system-notifications" aria-label="Permalink to &quot;System Notifications&quot;">​</a></h3><ul><li>Service status changes</li><li>Performance threshold alerts</li><li>Security warnings</li><li>Maintenance reminders</li></ul><h3 id="user-notifications" tabindex="-1">User Notifications <a class="header-anchor" href="#user-notifications" aria-label="Permalink to &quot;User Notifications&quot;">​</a></h3><ul><li>New user registrations</li><li>Failed login attempts</li><li>Permission changes</li><li>Account status updates</li></ul><h3 id="application-notifications" tabindex="-1">Application Notifications <a class="header-anchor" href="#application-notifications" aria-label="Permalink to &quot;Application Notifications&quot;">​</a></h3><ul><li>New app registrations</li><li>Authorization failures</li><li>Scope violations</li><li>Launch context errors</li></ul><h2 id="🎨-customization" tabindex="-1">🎨 Customization <a class="header-anchor" href="#🎨-customization" aria-label="Permalink to &quot;🎨 Customization&quot;">​</a></h2><h3 id="dashboard-widgets" tabindex="-1">Dashboard Widgets <a class="header-anchor" href="#dashboard-widgets" aria-label="Permalink to &quot;Dashboard Widgets&quot;">​</a></h3><p>Customize your dashboard view by:</p><ul><li>Rearranging metric cards</li><li>Hiding/showing specific statistics</li><li>Setting custom refresh intervals</li><li>Configuring alert thresholds</li></ul><h3 id="theme-options" tabindex="-1">Theme Options <a class="header-anchor" href="#theme-options" aria-label="Permalink to &quot;Theme Options&quot;">​</a></h3><ul><li>Light mode for daytime use</li><li>Dark mode for extended sessions</li><li>System-based automatic switching</li><li>High contrast accessibility mode</li></ul><h2 id="📈-performance-insights" tabindex="-1">📈 Performance Insights <a class="header-anchor" href="#📈-performance-insights" aria-label="Permalink to &quot;📈 Performance Insights&quot;">​</a></h2><h3 id="trending-data" tabindex="-1">Trending Data <a class="header-anchor" href="#trending-data" aria-label="Permalink to &quot;Trending Data&quot;">​</a></h3><p>The dashboard shows trends for:</p><ul><li>User growth over time</li><li>Application usage patterns</li><li>OAuth success rates</li><li>FHIR server performance</li><li>System resource utilization</li></ul><h3 id="comparative-analytics" tabindex="-1">Comparative Analytics <a class="header-anchor" href="#comparative-analytics" aria-label="Permalink to &quot;Comparative Analytics&quot;">​</a></h3><ul><li>Month-over-month growth</li><li>Peak usage periods</li><li>Error pattern analysis</li><li>Performance bottleneck identification</li></ul><h2 id="🔧-troubleshooting" tabindex="-1">🔧 Troubleshooting <a class="header-anchor" href="#🔧-troubleshooting" aria-label="Permalink to &quot;🔧 Troubleshooting&quot;">​</a></h2><h3 id="common-dashboard-issues" tabindex="-1">Common Dashboard Issues <a class="header-anchor" href="#common-dashboard-issues" aria-label="Permalink to &quot;Common Dashboard Issues&quot;">​</a></h3><p><strong>Dashboard not loading:</strong></p><ul><li>Check internet connection</li><li>Verify authentication status</li><li>Clear browser cache</li><li>Check console for errors</li></ul><p><strong>Data not updating:</strong></p><ul><li>Verify WebSocket connection</li><li>Check system health status</li><li>Refresh the page manually</li><li>Contact system administrator</li></ul><p><strong>Missing metrics:</strong></p><ul><li>Ensure proper permissions</li><li>Check data source availability</li><li>Verify system components are running</li><li>Review error logs</li></ul><h2 id="🚀-getting-started-tips" tabindex="-1">🚀 Getting Started Tips <a class="header-anchor" href="#🚀-getting-started-tips" aria-label="Permalink to &quot;🚀 Getting Started Tips&quot;">​</a></h2><ol><li><strong>First Login</strong>: Review all system health indicators</li><li><strong>Set Preferences</strong>: Configure refresh rates and notifications</li><li><strong>Explore Metrics</strong>: Click on cards for detailed views</li><li><strong>Test Actions</strong>: Try quick action buttons to navigate</li><li><strong>Monitor Trends</strong>: Check back regularly for pattern recognition</li></ol><p>The dashboard serves as your command center for the entire SMART on FHIR platform, providing the visibility and control needed for effective healthcare application management.</p>',74)])])}const m=t(o,[["render",r]]);export{g as __pageData,m as default};
